INSERT INTO variete (espece_id, nom, descriptif, bio, cycle_jours, couleur_legume, taille_fixe_legume, taille_min_legume, taille_max_legume, espacement_entre_les_plants, espacement_entre_les_lignes, type_ensoleillement, type_feuillage, hauteur_adulte_min, hauteur_adulte_max,duree_de_germination, temperature_min_de_germination, cycle_de_vie, rusticite_plante, date_semis_min, date_semis_max,duree_avant_recolte, type_de_sol, conseil_plantation) VALUES
	 (1,'Potager de Vilvorde','Ancienne variété régionale belge, très productive, aux fruits de calibre moyen, bien ronds et rouges. Bonne résistance aux maladies. Bien adapté aux régions humides. Croissance indéterminée.',1,75,'rouge',NULL,100.00,200.00,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','60-90 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands. Arroser régulièrement sans mouiller le feuillage.'),
	 (1,'Cornue des Andes','Ancienne variété originaire des Andes. Très productive. Fruits rouges, allongés en forme de gros piment. Charnue avec très peu de graines. Variété de mi-saison. Croissance indéterminée. Saveur douce sans acidité.',1,90,'rouge',NULL,150.00,180.00,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','80-100 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tuteurage solide recommandé. Tailler les gourmands. Arrosage régulier sans mouiller le feuillage. Paillage au pied.'),
	 (1,'Géante d''Orembourg','Variété de type beefsteak originaire de Russie occidentale. Très productive, elle produit de gros fruits ronds de couleur rouge cramoisi pouvant atteindre près de 1 kg. Chair dense, saveur douce, excellente qualité gustative. Variété tardive. Croissance indéterminée.',1,90,'rouge cramoisi',NULL,NULL,1000.00,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','80-100 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands. Arrosage régulier sans mouiller le feuillage. Tuteurage recommandé pour supporter les gros fruits.'),
	 (1,'Merveille des marchés','Très ancienne variété française de croissance compacte et vigoureuse. Fruits ronds et lisses avec peu de graines. Très savoureuse, idéale pour les farcis. Résistante. Variété de mi-saison. Croissance indéterminée.',1,75,'rouge',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','60-90 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands. Arrosage régulier sans mouiller le feuillage. Variété compacte et facile de culture.'),
	 (1,'Roma','Variété vigoureuse et productive. Fruit de taille moyenne, oblong, charnu et peu juteux mais savoureux. Idéal pour conserve. Variété de mi-saison à croissance déterminée. Variété italienne.',1,75,'rouge',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','60-90 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Croissance déterminée : paillez et palissez sans tailler les gourmands. Arrosage régulier sans mouiller le feuillage.'),
	 (1,'Cœur de bœuf','Variété ancienne très productive, originaire d''Italie (Cuor di Bue). Fruit en forme de cœur de bœuf, volumineux (300-700g), de taille moyenne à grande, à chair sucrée, dense et très juteuse avec peu de graines. Très savoureuse, convient pour les farcis et salades. Variété tardive à croissance indéterminée. Rendement 3-6 kg par plant.',1,90,'rouge',NULL,300.00,700.00,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','80-100 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tuteurage solide recommandé pour supporter le poids des gros fruits. Tailler les gourmands. Arrosage régulier sans mouiller le feuillage.'),
	 (1,'Ananas Noir','Variété belge de type ananas. Gros fruit pourpre veiné de rouge et de vert. Charnu avec peu de graines. Très bonne qualité gustative. Variété de mi-saison à croissance indéterminée. Fruits colorés et striés très originaux.',1,90,'pourpre veiné rouge et vert',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','80-100 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Arrosage régulier sans mouiller le feuillage.'),
	 (1,'San Marzano','Variété italienne de type Roma. Très vigoureuse. Fruit rouge allongé se terminant en pointe, à chair ferme, poussant en grappe. Saveur douce. Idéale pour la conserve, sauces et coulis. Variété tardive à croissance indéterminée.',1,75,'rouge',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','60-90 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Arrosage régulier sans mouiller le feuillage.'),
	 (1,'Marmande','Variété ancienne du sud-ouest de la France, vigoureuse et productive. Fruit rouge vif à chair ferme, sucrée et parfumée. Très bonne qualité gustative. Très appréciée tant pour la culture que pour la cuisine. Variété de mi-saison à croissance semi-déterminée.',1,75,'rouge vif',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','60-90 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Croissance semi-déterminée : tailler légèrement les gourmands. Arrosage régulier sans mouiller le feuillage.'),
	 (1,'Cerise Tempête de Sable','Variété régionale vigoureuse et productive, aux fruits moyens légèrement aplatis, blanc crème. Chair peu acide, saveur douce, peu aromatique. Peau fine. Croissance indéterminée. Précocité hâtive.',1,60,'jaune',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','50-70 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Arrosage régulier sans mouiller le feuillage.'),
	 (1,'Sasha Altaï','Variété sibérienne très précoce. Fruit rouge vif ronds. Chair pleine et juteuse. Saveur douce et de bonne qualité gustative. Variété précoce à croissance indéterminée. Originaire de Sibérie.',1,60,'rouge vif',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','50-70 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Arrosage régulier sans mouiller le feuillage.'),
	 (1,'Black Cherry','Variété de tomate cerise productive et rustique. Fruit noir du calibre d''une grosse cerise. Saveur sucrée. Très bonne qualité gustative. Variété précoce à croissance indéterminée. Plus productive et précoce que les variétés à gros fruits.',1,60,'noire',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','50-70 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Variété rustique et facile à cultiver, peut être cultivée en pot.'),
	 (1,'Noire de Crimée','Variété vigoureuse. Fruit rond sucré de couleur bordeaux presque noir. Chair dense et sucrée. Très appréciée par les enfants par son absence d''acidité. Variété de mi-saison à croissance indéterminée. Fruits très sucrés et savoureux.',1,90,'bordeaux noir',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','80-100 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Arrosage régulier sans mouiller le feuillage.'),
	 (1,'Yellow Belgian','Très ancienne variété régionale belge. Vigoureuse donnant de gros fruits jaune orange. Chair pleine et juteuse, un peu sucrée, de bonne qualité gustative. Variété de mi-saison à croissance indéterminée. Variété ancienne belge.',1,75,'jaune orange',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','60-90 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Arrosage régulier sans mouiller le feuillage.'),
	 (1,'Rose de Berne','Ancienne variété suisse. Gros fruit rose à chair épaisse et très sucrée. Très savoureuse, c''est l''une des plus appréciées. Très bon rendement et bonne résistance aux maladies. Variété de mi-saison à croissance indéterminée.',1,75,'rose',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','60-90 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Arrosage régulier sans mouiller le feuillage.'),
	 (1,'Olirose de St Domingue','Ancienne variété précoce et très productive. Fruit moyen rose foncé de forme ovale légèrement pointu. Chair ferme de bonne qualité gustative. Croissance indéterminée. Variété très productive.',1,60,'rose foncé',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','50-70 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Arrosage régulier sans mouiller le feuillage.'),
	 (1,'Black Prince','Excellente variété productive originaire de Sibérie. Fruit rouge pourpre de taille moyenne de forme ronde bien régulière. Saveur douce dépourvue d''acidité. Variété de mi-saison à croissance indéterminée. Moins sujette à l''éclatement et plus précoce que Noire de Crimée.',1,75,'rouge pourpre',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','60-90 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Arrosage régulier sans mouiller le feuillage.'),
	 (1,'Pamplemousse du Grand-Père','Excellente variété française. Gros fruit côtelé légèrement aplati orangé voilé de rose aussi bien sur l''épiderme que dans la chair. Chair charnue juteuse sans acidité sucrée. Excellente saveur. Moins tardive que la tomate Ananas. Variété de mi-saison à croissance indéterminée.',1,75,'orange voilé de rose',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','60-90 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Arrosage régulier sans mouiller le feuillage.'),
	 (1,'Green Zebra','Variété vigoureuse et productive produisant de magnifiques tomates vertes rayées de jaune de calibre moyen. Chair douce et ferme. Bonne conservation. Variété de mi-saison à croissance indéterminée. Fruits très originaux et attrayants.',1,75,'verte rayée jaune',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','60-90 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Arrosage régulier sans mouiller le feuillage.'),
	 (1,'Cerise Calabash Rouge','Très ancienne variété très précoce aux fruits de calibre moyen de forme irrégulière légèrement aplatis. Chair ferme et sucrée bonne qualité gustative. Croissance indéterminée. Plus productive et précoce que les variétés à gros fruits.',1,60,'rouge',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','50-70 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Peut être cultivée en pot. Arrosage régulier.'),
	 (1,'Gloire de Malines','Ancienne variété régionale belge dont on retrouve des traces dès les années 1930. Tomate très productive donnant des fruits rouges ronds lisses de taille moyenne. Chair légèrement farineuse juteuse parfumée peu acide. Variété de mi-saison à croissance indéterminée.',1,75,'rouge',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','60-90 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Arrosage régulier sans mouiller le feuillage.'),
	 (1,'Gloire de Versailles','Ancienne variété française précoce très productive. Fruit rouge bien lisse légèrement aplati de taille moyenne. Chair pleine bonne saveur. Variété à croissance indéterminée. Très productive et précoce.',1,60,'rouge',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','50-70 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Arrosage régulier sans mouiller le feuillage.'),
	 (1,'Cerise Jaune Ronde','Variété ancienne précoce très productive aux fruits jaune or. Chair sucrée bonne qualité gustative surtout en début de saison. Attention en fin de saison aux risques d''éclatement. Croissance indéterminée.',1,60,'jaune or',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','50-70 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Arrosage régulier, attention à l''éclatement en fin de saison.'),
	 (1,'Cerise Miel du Mexique','Ancienne variété de tomate cerise rouge. Plutôt tardive très productive. Fruit rond 2,5 cm diamètre formant belles grappes. Chair juteuse saveur douce très sucrée à maturité complète. Bonne résistance sécheresse et éclatement. Croissance indéterminée.',1,70,'rouge',25.00,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','50-70 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Peut être cultivée en pot. Arrosage régulier.'),
	 (1,'Jaune St Vincent','Variété de mi-saison donnant de beaux fruits légèrement aplatis côtelés. Chair juteuse sucrée légèrement acidulée. Parfaite en salade. Fruits jaunes très originaux.',1,75,'jaune',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','60-90 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Arrosage régulier sans mouiller le feuillage.'),
	 (1,'Purple Calabash','Variété tardive productive vigoureuse. Très beaux fruits rouge brun très foncé taille moyenne forme très irrégulière plissée aplatie. Saveur douce parfumée. Croissance indéterminée. Adaptée aux climats arides sécheresses.',1,90,'rouge brun très foncé',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','80-100 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Excellente résistance à la sécheresse.'),
	 (1,'Voyage','Variété productive précoce aux curieux fruits très difformes. Les morceaux se détachent très facilement sans abimer le reste du fruit. Chair épaisse juteuse sucrée. Croissance indéterminée. Fruits très originaux et faciles à partager.',1,90,'rouge',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','80-100 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Arrosage régulier sans mouiller le feuillage.'),
	 (1,'Gregory Altaï','Variété ancienne originaire des monts de l''Altaï en Sibérie. Précoce à croissance indéterminée produisant gros fruits rose violacé type beefsteak 200-500g. Aplatis côtelage léger pédoncule. Chair dense ferme juteuse saveur douce équilibrée. Vigoureuse plus 2m. S''adapte climats frais chauds.',1,60,'rose violacé',NULL,200.00,500.00,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','50-70 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Excellent pour régions froides et saisons courtes.'),
	 (1,'Lime Green','Variété tomate verte très productive mi-saison. Fruits vert aux reflets jaune taille moyenne. Chair juteuse saveur légèrement acidulée. Adaptée culture en pot. Croissance déterminée. Fruits très originaux vert lime.',1,75,'vert reflets jaune',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','60-90 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Croissance déterminée : paillez sans tailler les gourmands. Peut être cultivée en pot. Arrosage régulier.'),
	 (1,'Tigerella','Magnifique variété tomate rouge très précoce productive originaire d''Angleterre. Fruit rouge zébré jaune grosseur gros abricot. Très savoureuse. Croissance indéterminée assez vigoureuse. Fruits très originaux rayés.',1,60,'rouge zébré jaune',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','50-70 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tailler les gourmands pour stimuler la formation de beaux fruits. Arrosage régulier sans mouiller le feuillage.'),
	 (1,'Ananas','Très ancienne variété tardive originaire États-Unis. Gros fruits pouvant atteindre 1kg couleur jaune veinée rouge. Chair très ferme ressemblant chair ananas. Peu graines. Très savoureuse. Croissance indéterminée. Spectaculaire.',1,90,'jaune veiné rouge',NULL,500.00,1000.00,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','80-100 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Tuteurage solide indispensable. Tailler les gourmands. Arrosage régulier sans mouiller le feuillage.'),
	 (1,'Cerise Jaune Cocktail Clémentine','Variété précoce vigoureuse productive donnant nombreux petits fruits jaune orangé une centaine par bouquet. Chair sucrée juteuse. Délicieuse apéro confiture. Croissance déterminée. Très productive en grappes.',1,60,'jaune orangé',NULL,NULL,NULL,50,100,'plein soleil',NULL,100,200,'7-10 jours',20,'annuelle','Gélif (5° à 0°)','février','avril','50-70 jours','Tous types','Semez à chaud (20-24°) de février à avril. Repiquez en godet à 2-4 feuilles. Plantez à 50 x 80 cm après les dernières gelées. Croissance déterminée : paillez sans tailler les gourmands. Peut être cultivée en pot. Très productif.'),
